from collections import deque
class Solution:

def solve(self, maxSize, operations: list[int]) -> bool:
queue = deque()
for i in range(len(operations)):
if operations[i] == -1 and not queue:
return False
else if operations[i] == -1:
queue.popleft()
else:
queue.append(operations[i])
return True

# Test the function
solution = Solution()
print(solution.solve(10000, [5, 1, 2, 1, -1, 1, 2, -1, 1, 3, -1, -1, -1]))

