#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
bool solve(int maxSize, vector<int>& operations) {
queue<int> queue;
for (int i = 0; i < operations.size(); i++) {
if (operations[i] == -1 && queue.empty()) {
return false;
}
else if (operations[i] == -1) {
queue.pop_front();
}
else {
queue.push_back(operations[i]);
}
}
return true;
}
};

